SELECT AVG(crash_rate) AS average_crash_rate
FROM application_metrics
WHERE app_id = 0 AND metric_date = '2022-01-01';

SELECT AVG(battery_level) AS average_battery_level
FROM device_metrics
WHERE device_id = 1;

SELECT SUM(downloads) AS total_downloads
  FROM applications
  WHERE app_id = 1;

SELECT AVG(user_satisfaction) AS average_user_satisfaction
FROM application_metrics
WHERE app_id = 1 AND metric_date BETWEEN '2022-01-01' AND '2022-12-31';
